import{_ as t,o as r,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"49. Breaks","description":"","frontmatter":{"title":"49. Breaks","eba":"Allied Health Professionals 2021-2026","topics":["hours","shift-work","rosters","breaks"]},"headers":[],"relativePath":"ebas/allied-health/hours-of-work/49-breaks.md","filePath":"ebas/allied-health/hours-of-work/49-breaks.md"}'),s={name:"ebas/allied-health/hours-of-work/49-breaks.md"};function n(i,e,l,h,p,d){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_49-breaks" tabindex="-1">49. Breaks <a class="header-anchor" href="#_49-breaks" aria-label="Permalink to &quot;49. Breaks&quot;">​</a></h1><p><strong>49.1</strong> Meal Breaks</p><p><strong>(a)</strong> Entitlement to a Meal Break</p><p><strong>(i)</strong> Employees other than those working Shift duty An unpaid meal break of at least 30 minutes but not more than 60 minutes will be allowed during each rostered period of duty (Monday to Friday inclusive) to Employees, other than those working shift duty.</p><p><strong>(ii)</strong> Employees rostered for shift duty A meal break of 30 minutes per shift will be allowed for Employees rostered for shift duty and will be counted as time worked.</p><p><strong>(b)</strong> Timing of a meal break A meal break will, where reasonably practicable, commence no earlier than three (3) hours after the commencement of the Employee’s period of duty, and must</p><p>conclude no later than six (6) hours after the commencement of the Employee’s period of duty, unless otherwise agreed by the Employer and Employee.</p><p><strong>(c)</strong> Meal break not taken</p><p><strong>(i)</strong> The Employer will ensure that, wherever reasonably practicable, an Employee is able to take their meal break and is not required to perform any work during their meal break.</p><p><strong>(ii)</strong> Escalation process The Employer will describe, in writing, the steps to be taken where an Employee does not take their meal break to ensure that: A. wherever possible, the meal break is rescheduled and taken during the shift; and B. consideration is given to what caused the Employee to miss the scheduled meal break and whether any additional action is required to address those causes to reduce the likelihood of recurrence.</p><p><strong>(iii)</strong> Payment for meal break not taken Where an Employee is unable to take a meal break (including where an Employee is not free from duty as described at subclause 49.3(b)) the Employee will be paid for the meal break as time worked at their ordinary rate plus 50%.</p><p><strong>(d)</strong> Review of meal breaks for Employees rostered for shift duty The BPECC will review the provisions of this clause 49 relating to meal breaks for Employees rostered for shift duty during the life of this Agreement with a view to members of BPECC trying to identify potential changes that more closely align their entitlement to that of other Employees in a way that does not cause a detriment to them.</p><p><strong>49.2</strong> Rest/Tea breaks</p><p><strong>(a)</strong> An Employee will be entitled to a paid ten (10) minute tea break for each four (4) hours of ordinary duty or part thereof which will be counted as time worked.</p><p><strong>(b)</strong> Nothing in this subclause 49.2 prevents an Employee requesting and Employer agreeing for a Rest/Tea break to be at a specific time.</p><p>Examples: 1. An Employee working a six and a half (6.5) hour shift is entitled to two (2) ten minute tea breaks. 2. An Employee working a four (4) hour shift will be entitled to one (1) ten minute tea break.</p><p><strong>49.3</strong> Allocating Meal and Rest/Tea Breaks</p><p><strong>(a)</strong> The Employer will ensure that time is allocated consistent with this clause 49 so that the Employee can take their meal breaks and rest/tea breaks.</p><p><strong>(b)</strong> An Employee must be free from duty during their meal break and tea/rest break, and can use the time as they wish, including leaving the work area or the Employer’s premises.</p><p><strong>(c)</strong> An Employee must be given and cannot be required to work during their tea/rest break.</p><p><strong>49.4</strong> Staff meetings, in-house training and in-house professional development</p><p><strong>(a)</strong> Except where it is not reasonably practicable, staff meetings, in-house training and/or in-house professional development will not be conducted during an Employee’s meal break or tea/rest break.</p><p><strong>(b)</strong> Where staff meetings, in-house training and/or in-house professional development are conducted:</p><p><strong>(i)</strong> during an Employee’s meal break, the Employee will wherever possible be allocated an alternative meal break during the shift. Where it is not possible for the Employee to be allocated an alternative meal break during the shift, subclause 49.1(c)(iii) applies;</p><p><strong>(ii)</strong> during an Employee’s tea/rest break, the Employee will be allocated an alternative tea/rest break during the shift.</p><p><strong>49.5</strong> Clothing and PPE change Where an Employee performs a role that requires changing into or out of specific clothes and/or personal protective equipment (PPE) that are necessary to perform work, the Employer will ensure the Employee is provided with time to do this during their working hours.</p>',26)])])}const g=t(s,[["render",n]]);export{u as __pageData,g as default};
